-- ── Mailu ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Mailu is a free, open-source mail server distribution packaged as Docker images, bundling Postfix, Dovecot, Rspamd, and Roundcube for self-hosted email.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Mailu Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Mailu review: an open-source, Docker-based mail server bundling Postfix, Dovecot, Rspamd, and Roundcube for self-hosted email. Features and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Mailu is a free and open-source mail server distribution designed to let administrators self-host a full-featured email platform using Docker containers rather than manually configuring separate mail server components. The project's GitHub repository was created in January 2016, and it has grown from a small administration-interface experiment for Postfix into a full mail server stack maintained by a community of contributors under the Mailu organization. Rather than being a single product built by one company, Mailu bundles and orchestrates several proven open-source mail components into a reproducible, container-based deployment: Postfix handles SMTP mail transport, Dovecot provides IMAP and POP3 mailbox access, Rspamd performs spam filtering and message scoring, and Roundcube (or an alternative webmail client) offers a browser-based inbox. All components and Mailu's own configuration code are released under the MIT license, and the software is free to use, modify, and redistribute. Mailu provides a setup wizard that generates a docker-compose.yml file and environment configuration tailored to the administrator's domain, storage, and feature choices, which significantly lowers the barrier to running a modern, secure mail server compared to configuring Postfix and Dovecot by hand. Security and deliverability features are built in, including enforced TLS, DANE, MTA-STS, automatic Let's Encrypt certificate provisioning, outgoing DKIM signing, and antivirus scanning of attachments. A web-based admin interface allows domain and user management, alias creation, and account-level configuration without needing to edit config files directly. Mailu targets self-hosting enthusiasts, small businesses, nonprofits, and privacy-conscious organizations that want full control over their email infrastructure instead of relying on Google Workspace, Microsoft 365, or other hosted providers. The recommended minimum footprint is around 2 GB of total system memory. Because Mailu is entirely open source with no company behind it selling subscriptions, there is no official pricing model beyond the cost of the server infrastructure an administrator chooses to run it on; some third-party hosting providers offer managed Mailu deployments for a fee, but these are independent of the core project. Mailu's closest alternatives are docker-mailserver, Mail-in-a-Box, iRedMail, Modoboa, and Poste.io, all of which serve the same self-hosted email niche with different tradeoffs in configurability, admin UI polish, and component choice. Mailu differentiates itself with a strong focus on Docker-native deployment, an actively maintained web admin panel, and a security-by-default posture (TLS, DANE, MTA-STS, DKIM enabled out of the box), making it a popular choice among homelab and small-organization administrators who want a modern, GUI-managed mail stack without vendor lock-in.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'fcb91d77-94ad-4a0c-b605-9adaf3d6225f';

