INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('75720a0f-3359-4066-8426-dccd1160a142', $q$SMTP test server$q$, $q$Runs a lightweight SMTP server that intercepts outgoing application emails instead of delivering them to real recipients.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('75720a0f-3359-4066-8426-dccd1160a142', $q$Web-based email viewer$q$, $q$Modern dashboard for browsing, searching, and inspecting captured emails, including HTML, plain text, and raw source views.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('75720a0f-3359-4066-8426-dccd1160a142', $q$REST API$q$, $q$Programmatic access to captured messages for use in automated integration and end-to-end test suites.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('75720a0f-3359-4066-8426-dccd1160a142', $q$Webhooks$q$, $q$Fires a JSON POST to a configurable URL whenever a new message is captured, useful for CI notifications and integrations.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('75720a0f-3359-4066-8426-dccd1160a142', $q$POP3 server support$q$, $q$Allows real email clients to connect and download captured test messages as if from a live mail server.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('75720a0f-3359-4066-8426-dccd1160a142', $q$HTML and spam checks$q$, $q$Built-in HTML/CSS email-client compatibility checking and a spam-score estimate for outgoing messages.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('75720a0f-3359-4066-8426-dccd1160a142', $q$Tagging and search$q$, $q$Organize and filter large volumes of captured test emails by tag, sender, subject, or content.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('75720a0f-3359-4066-8426-dccd1160a142', $q$Single lightweight binary$q$, $q$Distributed as a zero-dependency Go binary and Docker image, making it fast to deploy anywhere.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('75720a0f-3359-4066-8426-dccd1160a142', $q$Completely free and open source with no usage limits$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('75720a0f-3359-4066-8426-dccd1160a142', $q$Very low memory and CPU footprint compared to alternatives$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('75720a0f-3359-4066-8426-dccd1160a142', $q$Modern, fast web interface for inspecting emails$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('75720a0f-3359-4066-8426-dccd1160a142', $q$REST API and webhooks make it easy to integrate into automated test suites$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('75720a0f-3359-4066-8426-dccd1160a142', $q$Actively maintained with frequent releases$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('75720a0f-3359-4066-8426-dccd1160a142', $q$Requires self-hosting and basic server or Docker knowledge$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('75720a0f-3359-4066-8426-dccd1160a142', $q$No built-in team collaboration or user-permission features$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('75720a0f-3359-4066-8426-dccd1160a142', $q$No official hosted/cloud version for teams that prefer SaaS$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('75720a0f-3359-4066-8426-dccd1160a142', $q$Limited to email capture and testing, not a full mail delivery platform$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('75720a0f-3359-4066-8426-dccd1160a142', $q$No vendor support contracts for enterprises that require SLAs$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('75720a0f-3359-4066-8426-dccd1160a142', $q$What is Mailpit used for$q$, $q$Mailpit is used by developers to capture and inspect emails sent by applications during development and testing, instead of delivering them to real inboxes.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('75720a0f-3359-4066-8426-dccd1160a142', $q$Is Mailpit free$q$, $q$Yes, Mailpit is free and open source with no paid tiers or usage limits.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('75720a0f-3359-4066-8426-dccd1160a142', $q$Does Mailpit require installation of dependencies$q$, $q$No, Mailpit ships as a single self-contained binary or Docker image with no external dependencies required.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('75720a0f-3359-4066-8426-dccd1160a142', $q$Can Mailpit be used in CI pipelines$q$, $q$Yes, its REST API and lightweight footprint make it well suited for automated integration testing in continuous integration environments.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('75720a0f-3359-4066-8426-dccd1160a142', $q$How is Mailpit different from MailHog$q$, $q$Mailpit is a modern, actively maintained successor to tools like MailHog, offering a faster interface, lower resource usage, and additional features such as webhooks and spam-score checks.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('75720a0f-3359-4066-8426-dccd1160a142', $q$Does Mailpit support real email clients$q$, $q$Yes, Mailpit includes an optional POP3 server that lets real email clients connect and download captured test messages.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('75720a0f-3359-4066-8426-dccd1160a142', $q$Local application development$q$, $q$Developers point their application's SMTP settings at Mailpit to capture and preview transactional emails without sending them to real users.$q$, $q$Backend and full-stack developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('75720a0f-3359-4066-8426-dccd1160a142', $q$Automated testing in CI pipelines$q$, $q$QA and DevOps teams use Mailpit's REST API to assert that expected emails were sent and to inspect their content as part of automated test suites.$q$, $q$QA engineers and DevOps teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('75720a0f-3359-4066-8426-dccd1160a142', $q$Email template and design review$q$, $q$Designers and marketers use Mailpit's HTML rendering and compatibility checks to review how transactional or marketing emails will look before launch.$q$, $q$Email developers and designers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('75720a0f-3359-4066-8426-dccd1160a142', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Self-hosted SMTP test server","Web-based email viewer","REST API and webhooks","POP3 server support","Unlimited test emails"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('75720a0f-3359-4066-8426-dccd1160a142', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Mailpit is an open-source SMTP testing tool and web-based email viewer built specifically for developers. Instead of sending test emails to real inboxes during development, applications are pointed at Mailpit's built-in SMTP server, which intercepts every message and stores it locally for inspection.$q$, $q$The tool is written in Go and ships as a single, zero-dependency binary alongside official Docker images, which makes it trivial to drop into local development environments, Docker Compose stacks, and continuous integration pipelines. It succeeded older tools like MailHog as the de facto standard for local email capture in many PHP, Laravel, WordPress, and Node.js projects.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('75720a0f-3359-4066-8426-dccd1160a142', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, Mailpit provides a modern web dashboard for viewing captured emails, showing the rendered HTML, plain-text version, raw source, headers, and attachments for every message it receives. It also includes an HTML/CSS compatibility checker and a spam-score estimate so developers can catch rendering and deliverability issues before an email ever reaches a real inbox.$q$, $q$Beyond the UI, Mailpit exposes a REST API for automated testing, an optional POP3 server for connecting real mail clients, and webhook notifications that fire whenever a new message arrives. It also supports STARTTLS with custom certificates, letting teams test secure SMTP configurations locally.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('75720a0f-3359-4066-8426-dccd1160a142', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Mailpit is completely free and open source; there are no paid tiers, seat limits, or usage caps. Anyone can self-host it on a laptop, a shared development server, or inside a CI pipeline at no cost.$q$, $q$Because there is no subscription model, teams can send unlimited test emails and run full test suites as often as they like without incurring per-email or per-seat charges, which is one of the main reasons it has become popular as a replacement for hosted sandbox services in cost-sensitive workflows.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('75720a0f-3359-4066-8426-dccd1160a142', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('75720a0f-3359-4066-8426-dccd1160a142', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a471ce8-ee50-4dac-866b-2e8ef45618fa', $q$Automated email sequences$q$, $q$Build multi-step, personalized cold email campaigns with automated follow-ups triggered by recipient behavior.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a471ce8-ee50-4dac-866b-2e8ef45618fa', $q$Lead Catcher$q$, $q$Automatically detects and categorizes replies as interested, not interested, or out of office so reps can prioritize outreach.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a471ce8-ee50-4dac-866b-2e8ef45618fa', $q$Email warmup and deliverability$q$, $q$Unlimited automated warmup to build and protect sender reputation across connected inboxes.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a471ce8-ee50-4dac-866b-2e8ef45618fa', $q$Power Phone Dialer$q$, $q$Built-in dialer with multiple phone numbers and unlimited North American calling minutes on higher-tier plans.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a471ce8-ee50-4dac-866b-2e8ef45618fa', $q$CRM integrations$q$, $q$Native integrations with Salesforce, Pipedrive, and HubSpot, plus 1,000+ apps via Zapier.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a471ce8-ee50-4dac-866b-2e8ef45618fa', $q$A/B testing$q$, $q$Test different subject lines, copy, and send times to optimize open and reply rates.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a471ce8-ee50-4dac-866b-2e8ef45618fa', $q$AI email writing$q$, $q$AI-assisted drafting of outreach copy and subject lines to speed up campaign creation.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7a471ce8-ee50-4dac-866b-2e8ef45618fa', $q$Social selling touches$q$, $q$Add social media touchpoints alongside email and calls for a multichannel outreach cadence.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7a471ce8-ee50-4dac-866b-2e8ef45618fa', $q$Bootstrapped, profitable company with a long operating track record since 2015$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7a471ce8-ee50-4dac-866b-2e8ef45618fa', $q$Combines email, phone, and social touches in one platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7a471ce8-ee50-4dac-866b-2e8ef45618fa', $q$Lead Catcher automates reply triage and saves rep time$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7a471ce8-ee50-4dac-866b-2e8ef45618fa', $q$Native CRM integrations reduce manual data entry$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7a471ce8-ee50-4dac-866b-2e8ef45618fa', $q$Simpler learning curve than heavier enterprise sales engagement suites$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7a471ce8-ee50-4dac-866b-2e8ef45618fa', $q$No permanently free plan$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7a471ce8-ee50-4dac-866b-2e8ef45618fa', $q$Higher tiers needed to unlock phone dialer and CRM integrations$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7a471ce8-ee50-4dac-866b-2e8ef45618fa', $q$Per-user pricing can add up for larger sales teams$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7a471ce8-ee50-4dac-866b-2e8ef45618fa', $q$Feature set is narrower than full-stack revenue platforms like Outreach or Salesloft$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7a471ce8-ee50-4dac-866b-2e8ef45618fa', $q$Some users report a learning curve for advanced sequence branching$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7a471ce8-ee50-4dac-866b-2e8ef45618fa', $q$What is Mailshake used for$q$, $q$Mailshake is used for cold email outreach and sales engagement, letting teams automate personalized email sequences combined with phone calls and social touches.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7a471ce8-ee50-4dac-866b-2e8ef45618fa', $q$Does Mailshake have a free plan$q$, $q$No, Mailshake does not offer a permanently free plan; its lowest tier, Starter, starts at 29 dollars per month.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7a471ce8-ee50-4dac-866b-2e8ef45618fa', $q$Who founded Mailshake$q$, $q$Mailshake was founded in 2015 by Sujan Patel, Robert Senoff, and Colin Mathews and is headquartered in Austin, Texas.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7a471ce8-ee50-4dac-866b-2e8ef45618fa', $q$Does Mailshake include a phone dialer$q$, $q$Yes, the Power Phone Dialer with multiple phone numbers and unlimited North American calling minutes is included on the Sales Engagement plan and above.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7a471ce8-ee50-4dac-866b-2e8ef45618fa', $q$What CRMs does Mailshake integrate with$q$, $q$Mailshake natively integrates with Salesforce, Pipedrive, and HubSpot, and connects to over 1,000 additional apps through Zapier.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7a471ce8-ee50-4dac-866b-2e8ef45618fa', $q$Is Mailshake good for agencies$q$, $q$Yes, Mailshake offers a dedicated Agency plan with unlimited email addresses for agencies managing outreach on behalf of multiple clients.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7a471ce8-ee50-4dac-866b-2e8ef45618fa', $q$Cold email lead generation$q$, $q$Sales development reps and founders use Mailshake to run automated, personalized cold email campaigns to generate new leads.$q$, $q$Sales development reps and founders$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7a471ce8-ee50-4dac-866b-2e8ef45618fa', $q$Multichannel sales outreach$q$, $q$Sales teams combine email, phone dialing, and social touches into a single automated sequence to increase response rates.$q$, $q$B2B sales teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7a471ce8-ee50-4dac-866b-2e8ef45618fa', $q$Agency client outreach management$q$, $q$Marketing and lead-generation agencies run outreach campaigns for multiple clients from one account using the Agency plan.$q$, $q$Marketing and lead-gen agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7a471ce8-ee50-4dac-866b-2e8ef45618fa', $q$Starter$q$, $q$$29/month$q$, $q$Monthly (or $25/month billed annually)$q$, NULL, $q$["1 email address","1,500 email sends per month","Unlimited uploaded contacts","Automated sequences and A/B testing","AI email writing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7a471ce8-ee50-4dac-866b-2e8ef45618fa', $q$Email Outreach$q$, $q$$49/month$q$, $q$Monthly (or $45/month billed annually)$q$, NULL, $q$["2 email addresses","Unlimited email sends","Unified inbox","CRM integrations (Salesforce, Pipedrive, HubSpot)","1,000+ Zapier integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7a471ce8-ee50-4dac-866b-2e8ef45618fa', $q$Sales Engagement$q$, $q$$99/month$q$, $q$Monthly (or $85/month billed annually)$q$, NULL, $q$["10 email addresses","5 phone numbers with Power Phone Dialer","Unlimited North American calling minutes","Lead temperature tracking","1-on-1 onboarding"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7a471ce8-ee50-4dac-866b-2e8ef45618fa', $q$Agency$q$, $q$Custom$q$, $q$Contact sales$q$, NULL, $q$["Unlimited email addresses","All Sales Engagement features","Multi-client management"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7a471ce8-ee50-4dac-866b-2e8ef45618fa', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Mailshake is a cold email outreach and sales engagement platform designed to help sales development reps, marketers, recruiters, and agencies automate personalized outbound campaigns at scale. Founded in 2015 in Austin, Texas, the company built its reputation as a bootstrapped, profitable alternative to venture-backed sales engagement suites.$q$, $q$Users connect their own email inbox and build multi-step sequences combining email, phone calls, and social touches, with the platform automatically pausing or branching sequences based on whether a prospect opens, clicks, or replies.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7a471ce8-ee50-4dac-866b-2e8ef45618fa', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Mailshake's core email features include mail merge personalization, A/B testing, automated follow-up sequences, unlimited email warmup to protect deliverability, and a Lead Catcher that auto-categorizes replies so reps can focus on genuinely interested prospects.$q$, $q$Higher-tier plans add a Power Phone Dialer with multiple phone numbers and unlimited North American calling minutes, social selling touches, native CRM integrations with Salesforce, Pipedrive, and HubSpot, and access to over 1,000 apps via Zapier, turning Mailshake into a broader multichannel sales engagement tool rather than a pure email sender.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7a471ce8-ee50-4dac-866b-2e8ef45618fa', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Mailshake offers three main per-user monthly plans: Starter at 29 dollars a month, Email Outreach at 49 dollars a month, and Sales Engagement at 99 dollars a month, each unlocking more email addresses, sending volume, and features like the phone dialer and CRM integrations at higher tiers.$q$, $q$There is no free-forever plan, but annual billing reduces the effective monthly cost on every tier. Agencies managing outreach for multiple clients can access a custom Agency plan with unlimited email addresses.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fcb91d77-94ad-4a0c-b605-9adaf3d6225f', $q$Docker-native deployment$q$, $q$Ships as a set of Docker images with a setup wizard that generates a ready-to-run docker-compose.yml configuration.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fcb91d77-94ad-4a0c-b605-9adaf3d6225f', $q$Full mail server stack$q$, $q$Bundles Postfix for SMTP, Dovecot for IMAP/POP3, Rspamd for spam filtering, and Roundcube for webmail.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fcb91d77-94ad-4a0c-b605-9adaf3d6225f', $q$Web-based admin panel$q$, $q$Manage domains, mailboxes, aliases, and user accounts through a browser-based interface without editing config files.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fcb91d77-94ad-4a0c-b605-9adaf3d6225f', $q$Built-in security defaults$q$, $q$Enforces TLS, DANE, and MTA-STS, with automatic Let's Encrypt certificate provisioning.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fcb91d77-94ad-4a0c-b605-9adaf3d6225f', $q$DKIM signing$q$, $q$Automatically signs outgoing mail with DKIM to improve deliverability and reduce spoofing.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fcb91d77-94ad-4a0c-b605-9adaf3d6225f', $q$Antivirus scanning$q$, $q$Scans incoming attachments for malware and blocks malicious files.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fcb91d77-94ad-4a0c-b605-9adaf3d6225f', $q$Webmail client$q$, $q$Includes Roundcube (or alternatives) so users can access their inbox directly from a browser.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fcb91d77-94ad-4a0c-b605-9adaf3d6225f', $q$MIT-licensed and free$q$, $q$All components and configuration code are released under the MIT license with no licensing fees.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fcb91d77-94ad-4a0c-b605-9adaf3d6225f', $q$Completely free and open source with no licensing costs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fcb91d77-94ad-4a0c-b605-9adaf3d6225f', $q$Docker-based setup significantly simplifies deploying a full mail stack$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fcb91d77-94ad-4a0c-b605-9adaf3d6225f', $q$Security features like DANE, MTA-STS, and DKIM are enabled by default$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fcb91d77-94ad-4a0c-b605-9adaf3d6225f', $q$Active community maintenance and regular releases$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fcb91d77-94ad-4a0c-b605-9adaf3d6225f', $q$Full administrative control over email infrastructure and data$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fcb91d77-94ad-4a0c-b605-9adaf3d6225f', $q$Requires server administration and Docker knowledge to operate$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fcb91d77-94ad-4a0c-b605-9adaf3d6225f', $q$Self-hosters are responsible for uptime, backups, and IP reputation$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fcb91d77-94ad-4a0c-b605-9adaf3d6225f', $q$Initial mail server reputation can take time to build for good deliverability$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fcb91d77-94ad-4a0c-b605-9adaf3d6225f', $q$No official commercial support or SLA from the core project$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fcb91d77-94ad-4a0c-b605-9adaf3d6225f', $q$Minimum resource requirements (around 2GB RAM) rule out very small servers$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fcb91d77-94ad-4a0c-b605-9adaf3d6225f', $q$What is Mailu used for$q$, $q$Mailu is used to self-host a complete email server, including SMTP sending, IMAP/POP3 mailbox access, spam filtering, and webmail, using Docker containers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fcb91d77-94ad-4a0c-b605-9adaf3d6225f', $q$Is Mailu free$q$, $q$Yes, Mailu is free and open source under the MIT license, with no charges for licenses, seats, or mailboxes.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fcb91d77-94ad-4a0c-b605-9adaf3d6225f', $q$What components does Mailu use$q$, $q$Mailu bundles Postfix for mail transport, Dovecot for IMAP/POP3, Rspamd for spam filtering, and Roundcube as an optional webmail client.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fcb91d77-94ad-4a0c-b605-9adaf3d6225f', $q$Does Mailu support Let's Encrypt$q$, $q$Yes, Mailu automatically provisions and renews TLS certificates through Let's Encrypt integration.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fcb91d77-94ad-4a0c-b605-9adaf3d6225f', $q$How much server capacity does Mailu need$q$, $q$Mailu recommends at least 2GB of total system memory with 1GB free for running the full stack.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fcb91d77-94ad-4a0c-b605-9adaf3d6225f', $q$What are alternatives to Mailu$q$, $q$Common alternatives include docker-mailserver, Mail-in-a-Box, iRedMail, Modoboa, and Poste.io, all of which offer self-hosted mail server stacks.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fcb91d77-94ad-4a0c-b605-9adaf3d6225f', $q$Self-hosted business email$q$, $q$Small businesses and nonprofits deploy Mailu to run their own email infrastructure instead of paying for hosted providers like Google Workspace.$q$, $q$Small businesses and nonprofits$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fcb91d77-94ad-4a0c-b605-9adaf3d6225f', $q$Privacy-focused personal email$q$, $q$Privacy-conscious individuals and homelab enthusiasts self-host Mailu to keep full control over their email data.$q$, $q$Homelab and privacy-focused users$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fcb91d77-94ad-4a0c-b605-9adaf3d6225f', $q$Managed hosting for clients$q$, $q$Hosting providers and system administrators deploy Mailu on behalf of clients who want dedicated, containerized mail infrastructure.$q$, $q$System administrators and hosting providers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fcb91d77-94ad-4a0c-b605-9adaf3d6225f', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full Postfix, Dovecot, Rspamd, and Roundcube mail stack","Docker-based deployment with setup wizard","Web admin panel for domains and mailboxes","Built-in TLS, DANE, MTA-STS, and DKIM"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fcb91d77-94ad-4a0c-b605-9adaf3d6225f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Mailu is an open-source, self-hosted mail server distribution delivered as a set of Docker images. Instead of manually installing and wiring together Postfix, Dovecot, and a webmail client, administrators use Mailu's setup utility to generate a ready-to-run docker-compose configuration for their domain.$q$, $q$The project started in 2016 as a small Postfix administration interface and has since evolved into a full mail platform combining Postfix (SMTP), Dovecot (IMAP/POP3), Rspamd (spam filtering), and Roundcube (webmail), all released under the MIT license and maintained by an open community of contributors.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fcb91d77-94ad-4a0c-b605-9adaf3d6225f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Mailu bundles a web-based admin interface for managing domains, mailboxes, and aliases, along with an optional webmail client so users can access email directly through a browser. Security is built in by default, with enforced TLS, DANE, MTA-STS, Let's Encrypt certificate automation, outgoing DKIM signing, and antivirus scanning of attachments.$q$, $q$The setup wizard generates the docker-compose.yml and environment files needed to deploy the full stack, which significantly reduces the manual configuration typically required to stand up a production-grade mail server.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fcb91d77-94ad-4a0c-b605-9adaf3d6225f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Mailu itself is completely free and open source under the MIT license; there is no vendor charging for licenses, seats, or mailbox counts. Administrators only pay for the server infrastructure they choose to run it on.$q$, $q$A handful of third-party hosting companies offer managed Mailu deployments for a fee, but these are independent services layered on top of the free, open-source core project.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fcb91d77-94ad-4a0c-b605-9adaf3d6225f', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6a6419f3-298f-4290-865a-3d302e88068a', $q$Live print monitoring$q$, $q$Real-time dashboard showing print progress, temperatures, and status for connected Klipper printers.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6a6419f3-298f-4290-865a-3d302e88068a', $q$Macro management$q$, $q$Create, organize, and trigger custom G-code macros directly from the web interface.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6a6419f3-298f-4290-865a-3d302e88068a', $q$Multi-printer support$q$, $q$Monitor and control multiple Klipper-powered printers from a single Mainsail instance.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6a6419f3-298f-4290-865a-3d302e88068a', $q$Webcam and timelapse integration$q$, $q$View multiple camera angles and generate automated timelapses via the moonraker-timelapse plugin.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6a6419f3-298f-4290-865a-3d302e88068a', $q$Slicer integration$q$, $q$Receive print jobs sent directly from supported slicers to streamline the print workflow.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6a6419f3-298f-4290-865a-3d302e88068a', $q$G-code console$q$, $q$Direct console access for sending G-code commands and diagnosing printer behavior.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6a6419f3-298f-4290-865a-3d302e88068a', $q$Customizable dashboard layout$q$, $q$Rearrange and configure dashboard panels to match individual workflow preferences.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6a6419f3-298f-4290-865a-3d302e88068a', $q$MainsailOS image$q$, $q$A ready-to-use Raspberry Pi OS image bundling Klipper, Moonraker, and Mainsail for quick setup.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6a6419f3-298f-4290-865a-3d302e88068a', $q$Completely free and open source$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6a6419f3-298f-4290-865a-3d302e88068a', $q$Modern, responsive, and highly customizable interface$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6a6419f3-298f-4290-865a-3d302e88068a', $q$Strong macro and multi-printer management features$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6a6419f3-298f-4290-865a-3d302e88068a', $q$Tight integration with the Klipper and Moonraker ecosystem$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6a6419f3-298f-4290-865a-3d302e88068a', $q$Active community development and MainsailOS simplifies setup$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6a6419f3-298f-4290-865a-3d302e88068a', $q$Requires Klipper and Moonraker already running, not a standalone app$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6a6419f3-298f-4290-865a-3d302e88068a', $q$Setup and configuration require some technical comfort$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6a6419f3-298f-4290-865a-3d302e88068a', $q$No official commercial support or SLA$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6a6419f3-298f-4290-865a-3d302e88068a', $q$Not compatible with non-Klipper firmware like stock Marlin$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6a6419f3-298f-4290-865a-3d302e88068a', $q$Advanced features rely on community plugins that vary in maintenance quality$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6a6419f3-298f-4290-865a-3d302e88068a', $q$What is Mainsail used for$q$, $q$Mainsail is used as a web-based interface for monitoring and controlling 3D printers that run the Klipper firmware.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6a6419f3-298f-4290-865a-3d302e88068a', $q$Is Mainsail free$q$, $q$Yes, Mainsail is free and open-source software with no paid tiers or licensing fees.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6a6419f3-298f-4290-865a-3d302e88068a', $q$Does Mainsail require Klipper$q$, $q$Yes, Mainsail connects to a printer running Klipper firmware through the Moonraker API server; it cannot control non-Klipper printers.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6a6419f3-298f-4290-865a-3d302e88068a', $q$What is the difference between Mainsail and Fluidd$q$, $q$Both are open-source web interfaces for Klipper printers built on Moonraker, but they differ in UI design and layout philosophy; choosing between them largely comes down to personal preference.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6a6419f3-298f-4290-865a-3d302e88068a', $q$What is MainsailOS$q$, $q$MainsailOS is a ready-to-use Raspberry Pi operating system image that bundles Klipper, Moonraker, and Mainsail together for a simplified setup.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6a6419f3-298f-4290-865a-3d302e88068a', $q$Can Mainsail manage multiple printers$q$, $q$Yes, Mainsail supports monitoring and controlling multiple Klipper-powered printers from a single dashboard.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6a6419f3-298f-4290-865a-3d302e88068a', $q$Home 3D printing monitoring$q$, $q$Hobbyists use Mainsail to monitor prints remotely, check temperatures, and manage macros from any browser on their network.$q$, $q$3D printing hobbyists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6a6419f3-298f-4290-865a-3d302e88068a', $q$DIY and Voron-style printer builds$q$, $q$Makers building custom Klipper-based printers, including Voron-style machines, use Mainsail as their primary control interface.$q$, $q$DIY 3D printer builders$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6a6419f3-298f-4290-865a-3d302e88068a', $q$Small-scale print farms$q$, $q$Small manufacturing shops and print farms use Mainsail's multi-printer support to oversee several machines from one dashboard.$q$, $q$Small print farms and makerspaces$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6a6419f3-298f-4290-865a-3d302e88068a', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Self-hosted web interface for Klipper printers","Live monitoring and macro management","Multi-printer support","Webcam and timelapse integration"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6a6419f3-298f-4290-865a-3d302e88068a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Mainsail is a free, open-source web interface for controlling and monitoring 3D printers that run the Klipper firmware. It connects to Moonraker, the API server that bridges Klipper to web clients, to provide a live, browser-based dashboard for starting prints, adjusting settings, and monitoring progress.$q$, $q$Developed by the mainsail-crew open-source community with its first release around 2020, Mainsail has become one of the two dominant web interfaces in the Klipper ecosystem, alongside Fluidd, and is commonly deployed on a Raspberry Pi connected to the printer's control board.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6a6419f3-298f-4290-865a-3d302e88068a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Mainsail provides real-time print monitoring with temperature graphs and progress statistics, macro management for custom G-code routines, and a console for direct G-code interaction and diagnostics. It supports multiple webcam angles and automated timelapse creation through the moonraker-timelapse plugin.$q$, $q$The interface also supports managing multiple printers from a single dashboard and can receive print jobs sent directly from supported slicers. MainsailOS, a companion Raspberry Pi image, bundles Klipper, Moonraker, and Mainsail together for a simplified initial setup.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6a6419f3-298f-4290-865a-3d302e88068a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Mainsail is completely free and open source, with no paid tiers, subscriptions, or licensing fees. It is self-hosted on the user's own Raspberry Pi or single-board computer alongside Klipper and Moonraker.$q$, $q$The project is sustained through voluntary community contributions via GitHub Sponsors rather than commercial sales, and there are no restrictions on the number of printers or users a self-hosted instance can support.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6a6419f3-298f-4290-865a-3d302e88068a', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6a6419f3-298f-4290-865a-3d302e88068a', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b946b0d-bbd9-4828-97ce-cd1fcb7ad0fd', $q$Tailwind CSS for email$q$, $q$Author email templates using Tailwind utility classes with a configuration tuned specifically for email client compatibility.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b946b0d-bbd9-4828-97ce-cd1fcb7ad0fd', $q$Vue component-based templates$q$, $q$Build reusable header, footer, and layout components as Vue single-file components instead of duplicating markup.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b946b0d-bbd9-4828-97ce-cd1fcb7ad0fd', $q$Automated CSS inlining$q$, $q$Build pipeline automatically inlines CSS and strips unused classes for maximum email client support.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b946b0d-bbd9-4828-97ce-cd1fcb7ad0fd', $q$Outlook fallback handling$q$, $q$Automatically applies email-safe fallbacks and fixes for Outlook's limited rendering engine.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b946b0d-bbd9-4828-97ce-cd1fcb7ad0fd', $q$Live dev server with HMR$q$, $q$Modern local development server with live preview, hot module reloading, and device-size resizing.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b946b0d-bbd9-4828-97ce-cd1fcb7ad0fd', $q$Email client compatibility checker$q$, $q$Built-in checks flag markup or CSS that may render inconsistently across major email clients.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b946b0d-bbd9-4828-97ce-cd1fcb7ad0fd', $q$Dark mode emulation$q$, $q$Preview how templates render in dark-mode-enabled inboxes before sending.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b946b0d-bbd9-4828-97ce-cd1fcb7ad0fd', $q$Vite plugin support$q$, $q$Can be used as a standalone CLI, a Node library, or embedded as a Vite plugin in frameworks like Laravel, Nuxt, or Astro.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b946b0d-bbd9-4828-97ce-cd1fcb7ad0fd', $q$Free and open source with no usage limits$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b946b0d-bbd9-4828-97ce-cd1fcb7ad0fd', $q$Leverages Tailwind CSS, giving a short learning curve for developers who already know it$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b946b0d-bbd9-4828-97ce-cd1fcb7ad0fd', $q$Automated CSS inlining and Outlook fallback handling save significant manual work$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b946b0d-bbd9-4828-97ce-cd1fcb7ad0fd', $q$Modern dev server experience with live preview and hot reloading$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b946b0d-bbd9-4828-97ce-cd1fcb7ad0fd', $q$Flexible integration as CLI, library, or Vite plugin$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b946b0d-bbd9-4828-97ce-cd1fcb7ad0fd', $q$Requires familiarity with Tailwind CSS and a JavaScript build toolchain$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b946b0d-bbd9-4828-97ce-cd1fcb7ad0fd', $q$Steeper learning curve for non-developers compared to drag-and-drop email builders$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b946b0d-bbd9-4828-97ce-cd1fcb7ad0fd', $q$No official hosted or SaaS version, must be run locally or in CI$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b946b0d-bbd9-4828-97ce-cd1fcb7ad0fd', $q$Premium starter kits are a separate paid purchase from the core framework$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b946b0d-bbd9-4828-97ce-cd1fcb7ad0fd', $q$Smaller community and ecosystem compared to MJML$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b946b0d-bbd9-4828-97ce-cd1fcb7ad0fd', $q$What is Maizzle used for$q$, $q$Maizzle is used to build production-ready HTML emails using Tailwind CSS, with an automated pipeline for CSS inlining, minification, and email client compatibility fixes.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b946b0d-bbd9-4828-97ce-cd1fcb7ad0fd', $q$Is Maizzle free$q$, $q$Yes, the core Maizzle framework, CLI, and Vite plugin are free and open source; only optional premium starter kits are sold separately.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b946b0d-bbd9-4828-97ce-cd1fcb7ad0fd', $q$Who created Maizzle$q$, $q$Maizzle was created by developer Cosmin Popovici and is maintained as an open-source project.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b946b0d-bbd9-4828-97ce-cd1fcb7ad0fd', $q$How is Maizzle different from MJML$q$, $q$Maizzle uses Tailwind CSS utility classes and Vue components for authoring, while MJML uses its own proprietary markup language; Maizzle offers a shorter learning curve for developers already familiar with Tailwind.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b946b0d-bbd9-4828-97ce-cd1fcb7ad0fd', $q$Can Maizzle be used with other frameworks$q$, $q$Yes, Maizzle can run as a standalone CLI, be used as a Node library, or be plugged in as a Vite plugin within frameworks like Laravel, Nuxt, SvelteKit, or Astro.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b946b0d-bbd9-4828-97ce-cd1fcb7ad0fd', $q$Does Maizzle support dark mode previews$q$, $q$Yes, Maizzle's development server includes dark mode emulation to preview how templates render in dark-mode-enabled inboxes.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6b946b0d-bbd9-4828-97ce-cd1fcb7ad0fd', $q$Transactional email development$q$, $q$Developers build and maintain transactional email templates (receipts, password resets, notifications) using reusable Maizzle components.$q$, $q$Backend and full-stack developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6b946b0d-bbd9-4828-97ce-cd1fcb7ad0fd', $q$Marketing email template systems$q$, $q$Marketing teams and agencies use Maizzle to build a component library of on-brand, tested email templates for campaigns.$q$, $q$Email marketers and agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6b946b0d-bbd9-4828-97ce-cd1fcb7ad0fd', $q$E-commerce and Shopify email kits$q$, $q$E-commerce teams use Maizzle, often alongside premium starter kits, to build transactional and promotional emails for online stores.$q$, $q$E-commerce teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6b946b0d-bbd9-4828-97ce-cd1fcb7ad0fd', $q$Open Source Framework$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Maizzle CLI and Vite plugin","Tailwind CSS email compilation pipeline","Live dev server with HMR","CSS inlining and Outlook fallbacks"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6b946b0d-bbd9-4828-97ce-cd1fcb7ad0fd', $q$Premium Starter Kits$q$, $q$Varies (one-time purchase)$q$, $q$One-time$q$, NULL, $q$["Pre-built transactional and e-commerce templates","Shopify email templates","Figma design system files"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6b946b0d-bbd9-4828-97ce-cd1fcb7ad0fd', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Maizzle is an open-source framework for building HTML emails with Tailwind CSS, created by developer Cosmin Popovici to solve the persistent pain of hand-coding table-based, inline-styled email markup for inconsistent email clients.$q$, $q$Developers author templates using Tailwind utility classes and Vue single-file components, and Maizzle's build pipeline compiles them into production-ready HTML with inlined CSS, minification, and Outlook-safe fallbacks, ready to paste into an email service provider or sending platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6b946b0d-bbd9-4828-97ce-cd1fcb7ad0fd', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Maizzle's build pipeline automatically inlines CSS, strips unused classes, minifies output, and applies email-client-specific fixes, particularly for Outlook's limited rendering engine. Its Tailwind configuration is tuned specifically for email, adjusting spacing and sizing utilities for maximum client compatibility.$q$, $q$The local development server offers live preview with hot reloading, device-size resizing, an email client compatibility checker, dark-mode emulation, and the ability to send test emails directly from the editor, giving developers a fast feedback loop that mirrors modern front-end tooling.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6b946b0d-bbd9-4828-97ce-cd1fcb7ad0fd', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core Maizzle framework, CLI, and Vite plugin are free and open source, distributed via npm with no license fees or usage limits for building and compiling email templates.$q$, $q$Separately, Maizzle's creator sells optional premium starter kits and pre-built email template packs (transactional, e-commerce, and Shopify templates) as one-time commercial purchases; these are add-on products distinct from the free open-source framework itself.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6b946b0d-bbd9-4828-97ce-cd1fcb7ad0fd', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Trust Flow and Citation Flow$q$, $q$Proprietary metrics estimating the quality (Trust Flow) and quantity (Citation Flow) of a site's backlink profile.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Site Explorer$q$, $q$Audit any domain's or URL's complete backlink profile, referring domains, and anchor text distribution.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Historic Index$q$, $q$Access historical backlink data spanning years to trace how a site's link profile has evolved.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Bulk Backlink Checker$q$, $q$Analyze backlink metrics for many URLs simultaneously, useful for large-scale audits.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Clique Hunter$q$, $q$Identify sites that link to multiple competitors but not to your own site, surfacing link-building targets.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Link Graph and Link Context$q$, $q$Visualize link relationships and the surrounding context of individual backlinks.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Topical Trust Flow$q$, $q$Assess the topical relevance and category of a site's referring domains.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Compare Sites$q$, $q$Side-by-side comparison of backlink profiles across multiple competing domains.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$One of the largest historic backlink indexes in the industry$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Trust Flow and Citation Flow are widely recognized and cited SEO metrics$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Deep, link-focused feature set for specialists and agencies$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Clique Hunter and bulk tools speed up link-building prospecting$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$API access available for teams that need programmatic data$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Narrower focus than all-in-one suites like Ahrefs or Semrush, no built-in keyword rank tracking or content tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Analysis Units credit system can be confusing for new users$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Pricing in euros may add currency conversion complexity for some customers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Interface feels dated compared to some modern SEO tool competitors$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$No permanently free full-featured plan, only a limited free backlink checker$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$What is Majestic used for$q$, $q$Majestic is used for backlink analysis, link-building research, and SEO audits, centered on its Trust Flow and Citation Flow metrics.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$What are Trust Flow and Citation Flow$q$, $q$Trust Flow estimates the quality of a site's backlinks based on proximity to trusted seed sites, while Citation Flow estimates the raw quantity or influence of links pointing to it; the two are often compared as a ratio.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$How much does Majestic cost$q$, $q$Majestic's Lite plan starts at 46.99 euros per month, with a Pro plan at 94.99 euros per month and an API plan at 379.99 euros per month, plus annual discounts.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$When was Majestic founded$q$, $q$Majestic began in 2004 as Majestic-12, an open-source web crawling project, and pivoted to a commercial SEO link-intelligence business in 2008.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Does Majestic have a free backlink checker$q$, $q$Yes, Majestic offers a limited free backlink checker tool on its website in addition to its paid subscription plans.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$What are Majestic's main competitors$q$, $q$Majestic's main competitors are Ahrefs, Semrush, and Moz, which offer backlink analysis as part of broader all-in-one SEO platforms.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Backlink audits$q$, $q$SEO professionals use Majestic's Site Explorer and Historic Index to audit a domain's full backlink profile and identify toxic or low-quality links.$q$, $q$SEO specialists and consultants$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Link-building prospecting$q$, $q$Link builders use Clique Hunter and Bulk Backlink Checker to find sites linking to competitors and identify outreach opportunities.$q$, $q$Link builders and digital PR teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Competitive SEO analysis$q$, $q$Agencies use Compare Sites and Topical Trust Flow to benchmark a client's backlink profile against competitors.$q$, $q$SEO agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Lite$q$, $q$€46.99/month$q$, $q$Monthly (or €39.16/month billed annually)$q$, NULL, $q$["Fresh Index access","Limited Site Explorer","1 million Analysis Units","Trust Flow and Citation Flow","Bulk Backlink Checker"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$Pro$q$, $q$€94.99/month$q$, $q$Monthly (or €79.16/month billed annually)$q$, NULL, $q$["Everything in Lite","Historic Index access","Clique Hunter","Raw data exports and custom reports","20 million Analysis Units"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$API$q$, $q$€379.99/month$q$, $q$Monthly (or €316.66/month billed annually)$q$, NULL, $q$["Everything in Pro","Full API access","5 users","100 million Analysis Units"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Majestic, often referred to as Majestic SEO, is a backlink analysis and link-intelligence platform that began in 2004 as Majestic-12, a volunteer-powered open web-crawling project in the United Kingdom, before pivoting to a commercial SEO tool in 2008. The company is headquartered in Birmingham, England.$q$, $q$Majestic is best known in the SEO industry for its Trust Flow and Citation Flow metrics, which separately estimate the quality and quantity of a website's backlink profile, and for maintaining one of the largest historic backlink indexes available to SEO practitioners.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Majestic's Site Explorer lets users audit any domain's full backlink profile, while the Bulk Backlink Checker and Clique Hunter tools help agencies and link builders audit many URLs at once and find link-building opportunities based on competitor gap analysis.$q$, $q$Additional tools include a Link Graph and Link Context visualization, Historic Index access for tracing how a link profile evolved over time, Compare Sites for competitive analysis, and Topical Trust Flow for assessing the topical relevance of referring domains.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cb838640-ef5a-4d9a-92b1-14717d41944f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Majestic prices its plans using a consumption-based Analysis Units credit system across three main tiers: Lite at 46.99 euros per month, Pro at 94.99 euros per month, and an API plan at 379.99 euros per month for developers needing programmatic access.$q$, $q$Annual billing offers a discount versus monthly pricing on all plans, and new customers on the Lite and Pro tiers get a 7-day money-back guarantee.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Visual scenario builder$q$, $q$Drag-and-drop flowchart interface for building automated workflows by connecting app modules.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$3,000+ app integrations$q$, $q$Pre-built connectors for thousands of cloud apps and APIs, plus support for custom HTTP requests.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Routers and filters$q$, $q$Branch workflow logic and apply conditional filters to control exactly when and how each step runs.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Scheduled and instant triggers$q$, $q$Run scenarios on a schedule down to the minute or trigger them instantly from webhooks and events.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Data transformation tools$q$, $q$Built-in functions for parsing, formatting, and transforming data as it moves between apps.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$AI agent orchestration$q$, $q$Incorporate large language model calls and AI-driven decision-making directly into automated scenarios.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Error handling routes$q$, $q$Define fallback paths and retries when a step in a scenario fails.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Team roles and templates$q$, $q$Share scenario templates and manage team member permissions on Teams and Enterprise plans.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Powerful visual, flowchart-based workflow builder handles complex branching logic$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Connects to over 3,000 apps and APIs$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Generally more affordable at scale than Zapier for comparable usage$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Detailed data inspection at every step makes debugging easier$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Backed by Celonis, providing enterprise-grade stability and continued investment$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Steeper learning curve than simpler linear automation tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Credit/operation-based pricing can be difficult to predict for complex scenarios$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Free plan is limited to two active scenarios$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Some advanced features require Pro or Teams tier$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Enterprise pricing requires contacting sales rather than transparent self-serve pricing$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$What is Make used for$q$, $q$Make is used to build no-code automated workflows, called scenarios, that connect different apps and APIs to move data and trigger actions automatically.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Was Make formerly called Integromat$q$, $q$Yes, Make was originally founded in 2012 as Integromat in Prague, Czech Republic, and was rebranded to Make in 2022 after being acquired by Celonis.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Who owns Make$q$, $q$Make is owned by Celonis, a process mining and execution management company that acquired Integromat in October 2020.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Does Make have a free plan$q$, $q$Yes, Make offers a Free plan with up to 1,000 operations per month and a maximum of two active scenarios.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$How is Make different from Zapier$q$, $q$Make uses a visual, flowchart-style builder that supports more complex branching logic and detailed data inspection, while Zapier uses a simpler linear trigger-and-action model; Make is often noted as more cost-effective at higher usage volumes.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Does Make support AI features$q$, $q$Yes, Make includes AI agent orchestration features that let scenarios call large language models and incorporate AI-driven decisions into automated workflows.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Marketing and sales workflow automation$q$, $q$Marketing and sales teams use Make to sync leads between CRMs, email tools, and spreadsheets automatically without manual data entry.$q$, $q$Marketing and sales operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Business process automation for SMBs$q$, $q$Small business owners use Make to automate repetitive administrative tasks like invoicing, notifications, and data syncing across tools.$q$, $q$Small business owners and solo founders$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Enterprise process integration$q$, $q$Enterprise IT and operations teams use Make's Enterprise tier to connect internal systems and orchestrate mission-critical automated processes at scale.$q$, $q$Enterprise IT and operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Free$q$, $q$$0/month$q$, $q$Monthly$q$, NULL, $q$["Up to 1,000 operations per month","Maximum 2 active scenarios","3,000+ app integrations","15-minute minimum scheduling interval"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Core$q$, $q$$9/month$q$, $q$Monthly (10,000 operations)$q$, NULL, $q$["Unlimited active scenarios","Scheduling down to the minute","Access to Make API","100 MB max file size"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Pro$q$, $q$$16/month$q$, $q$Monthly (10,000 operations)$q$, NULL, $q$["Everything in Core","Priority scenario execution","Custom variables","Full-text execution log search"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Teams$q$, $q$$29/month$q$, $q$Monthly (10,000 operations)$q$, NULL, $q$["Everything in Pro","Team roles and shared templates","Analytics dashboard and audit logs"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$Enterprise$q$, $q$Custom$q$, $q$Contact sales$q$, NULL, $q$["Everything in Teams","Custom functions and enterprise integrations","24/7 support","Advanced security features"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Make is a visual, no-code automation platform that lets users connect thousands of apps and APIs into automated workflows called scenarios, without writing code. It was founded in 2012 in Prague, Czech Republic, under the name Integromat, before being acquired by Celonis in 2020 and rebranded as Make in 2022.$q$, $q$Unlike simpler linear automation tools, Make uses a flowchart-style visual builder where users chain modules together with routers, filters, and branching logic, giving technical and non-technical users alike fine-grained control over complex, multi-step workflows.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Make's drag-and-drop scenario builder supports triggers, actions, routers for branching logic, filters for conditional execution, and built-in data transformation tools, all while letting users inspect the exact data flowing through each step for easier debugging.$q$, $q$The platform connects to over 3,000 apps and exposes a public API for custom integrations. Recent additions include AI agent orchestration features that let scenarios call large language models and make AI-driven decisions as part of automated workflows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bf487e99-d6ce-4329-b02b-a9efe905e265', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Make uses a credit-based pricing model, with a Free plan offering up to 1,000 operations per month and two active scenarios, and paid plans (Core, Pro, and Teams) starting around 9 dollars per month for 10,000 credits, scaling up with faster execution, priority processing, and team features.$q$, $q$An Enterprise tier with custom pricing adds custom functions, enterprise app integrations, 24/7 support, and advanced security controls for large organizations. Annual billing saves 15 percent or more across all paid tiers.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ac91ecc3-0c24-4414-be5b-9971df7a568d', $q$Real-time malware protection$q$, $q$Continuously monitors the device for malware, ransomware, and other threats using behavior-based detection.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ac91ecc3-0c24-4414-be5b-9971df7a568d', $q$On-demand scanning$q$, $q$Free scanner that checks a device for existing malware infections, widely used as a second-opinion tool.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ac91ecc3-0c24-4414-be5b-9971df7a568d', $q$Ransomware protection$q$, $q$Dedicated detection layer designed to block and remediate ransomware attacks before files are encrypted.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ac91ecc3-0c24-4414-be5b-9971df7a568d', $q$Privacy VPN$q$, $q$Built-in VPN service, now running on infrastructure from the 2024 AzireVPN acquisition, available on Plus and Ultimate tiers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ac91ecc3-0c24-4414-be5b-9971df7a568d', $q$Identity protection$q$, $q$Credit monitoring, dark web alerts, and personal data removal services included in the Ultimate tier.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ac91ecc3-0c24-4414-be5b-9971df7a568d', $q$Browser protection$q$, $q$Blocks malicious websites, phishing attempts, and unwanted ad trackers while browsing.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ac91ecc3-0c24-4414-be5b-9971df7a568d', $q$Endpoint detection and response$q$, $q$ThreatDown's business tier offers centralized visibility and response tools for IT teams managing many endpoints.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ac91ecc3-0c24-4414-be5b-9971df7a568d', $q$Multi-device support$q$, $q$Consumer plans cover multiple devices across Windows, Mac, Android, and iOS from a single subscription.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ac91ecc3-0c24-4414-be5b-9971df7a568d', $q$Strong reputation for behavior-based malware and ransomware detection$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ac91ecc3-0c24-4414-be5b-9971df7a568d', $q$Free on-demand scanner is useful as a second-opinion tool alongside other antivirus$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ac91ecc3-0c24-4414-be5b-9971df7a568d', $q$VPN and identity protection bundled into higher consumer tiers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ac91ecc3-0c24-4414-be5b-9971df7a568d', $q$60-day money-back guarantee on annual consumer plans$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ac91ecc3-0c24-4414-be5b-9971df7a568d', $q$Separate ThreatDown business line offers dedicated enterprise endpoint security$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ac91ecc3-0c24-4414-be5b-9971df7a568d', $q$Advertised prices are first-year promotional rates that increase significantly on renewal$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ac91ecc3-0c24-4414-be5b-9971df7a568d', $q$Free tier only offers on-demand scanning, not real-time protection$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ac91ecc3-0c24-4414-be5b-9971df7a568d', $q$VPN and identity protection require higher-priced tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ac91ecc3-0c24-4414-be5b-9971df7a568d', $q$Business and consumer products are managed as separate brands (ThreatDown vs Malwarebytes), which can be confusing$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ac91ecc3-0c24-4414-be5b-9971df7a568d', $q$Some users report the software can be more resource-intensive than lightweight competitors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ac91ecc3-0c24-4414-be5b-9971df7a568d', $q$What is Malwarebytes used for$q$, $q$Malwarebytes is used to detect and remove malware, ransomware, and other threats from computers and mobile devices, with paid tiers adding VPN and identity protection.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ac91ecc3-0c24-4414-be5b-9971df7a568d', $q$Is Malwarebytes free$q$, $q$Malwarebytes offers a free on-demand malware scanner, while real-time protection, VPN, and identity protection require a paid Standard, Plus, or Ultimate subscription.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ac91ecc3-0c24-4414-be5b-9971df7a568d', $q$Who founded Malwarebytes$q$, $q$Malwarebytes was founded in 2008 by Marcin Kleczynski, who began developing malware-removal tools as a teenager in 2004, and the company is headquartered in Santa Clara, California.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ac91ecc3-0c24-4414-be5b-9971df7a568d', $q$What is ThreatDown$q$, $q$ThreatDown is the rebranded business security division of Malwarebytes, launched in 2023, offering separate per-endpoint pricing and enterprise endpoint detection and response tools.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ac91ecc3-0c24-4414-be5b-9971df7a568d', $q$Does Malwarebytes include a VPN$q$, $q$Yes, the Plus and Ultimate consumer tiers include Malwarebytes Privacy VPN, which runs on infrastructure from the company's 2024 acquisition of AzireVPN.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ac91ecc3-0c24-4414-be5b-9971df7a568d', $q$Is Malwarebytes good enough to replace a full antivirus$q$, $q$Malwarebytes Standard and higher tiers provide real-time protection intended to work as a full antivirus replacement, though many users historically also ran it alongside another antivirus as a second-opinion scanner.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ac91ecc3-0c24-4414-be5b-9971df7a568d', $q$Malware and ransomware removal$q$, $q$Consumers use Malwarebytes to scan for and remove existing malware or ransomware infections from an already-compromised device.$q$, $q$Home consumers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ac91ecc3-0c24-4414-be5b-9971df7a568d', $q$Everyday device security with privacy tools$q$, $q$Privacy-conscious users subscribe to Malwarebytes Plus or Ultimate to combine real-time protection with a VPN and identity monitoring.$q$, $q$Privacy-conscious consumers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ac91ecc3-0c24-4414-be5b-9971df7a568d', $q$Business endpoint security$q$, $q$IT teams use ThreatDown, Malwarebytes's business product line, to centrally manage endpoint detection and response across company devices.$q$, $q$IT and security teams at small and midsize businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ac91ecc3-0c24-4414-be5b-9971df7a568d', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["On-demand malware scanning","Manual threat removal"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ac91ecc3-0c24-4414-be5b-9971df7a568d', $q$Standard$q$, $q$$59.99/year$q$, $q$Annual (promotional first-year rate)$q$, NULL, $q$["Real-time malware and ransomware protection","Browser protection","Multi-device coverage"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ac91ecc3-0c24-4414-be5b-9971df7a568d', $q$Plus$q$, $q$$79.99/year$q$, $q$Annual (promotional first-year rate)$q$, NULL, $q$["Everything in Standard","Privacy VPN","Ad and tracker blocking"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ac91ecc3-0c24-4414-be5b-9971df7a568d', $q$Ultimate$q$, $q$$139.99/year (first year)$q$, $q$Annual (promotional first-year rate, renews higher)$q$, NULL, $q$["Everything in Plus","Identity protection and credit monitoring","Dark web alerts","Personal data removal service"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ac91ecc3-0c24-4414-be5b-9971df7a568d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Malwarebytes is a cybersecurity company offering anti-malware, antivirus, VPN, and identity protection software for consumers, alongside a separately branded enterprise product line called ThreatDown. Its roots trace back to 2004, when founder Marcin Kleczynski began building malware-removal tools as a teenager, with the company formally founded in 2008 and headquartered in Santa Clara, California.$q$, $q$The brand built its reputation on a free malware-removal scanner that was downloaded onto hundreds of millions of computers, becoming a widely trusted second-opinion scanning tool used alongside traditional antivirus software before the company expanded into full real-time protection suites, VPN, and identity protection.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ac91ecc3-0c24-4414-be5b-9971df7a568d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Malwarebytes provides real-time malware and ransomware protection, on-demand scanning, and behavior-based threat detection designed to catch threats that traditional signature-based antivirus tools can miss. Higher tiers add a Privacy VPN, now running on infrastructure from its 2024 AzireVPN acquisition.$q$, $q$The top consumer tier, Ultimate, bundles identity protection features including credit monitoring, dark web alerts, and personal data removal services. On the business side, the ThreatDown product line offers centralized endpoint detection and response for IT teams managing many devices.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ac91ecc3-0c24-4414-be5b-9971df7a568d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Malwarebytes offers a free on-demand malware scanner alongside three paid consumer tiers: Standard (real-time protection, from around 59.99 dollars per year), Plus (adds Privacy VPN, from around 79.99 dollars per year), and Ultimate (adds identity protection and credit monitoring, from around 139.99 dollars for the first year).$q$, $q$Advertised prices are typically first-year promotional rates that renew at a higher standard price. All annual consumer plans include a 60-day money-back guarantee. Business customers use the separately branded ThreatDown pricing, with per-endpoint annual plans starting around 69 dollars per endpoint.$q$]::text[], 2);
